/**
 * XUI 布局组件模块。
 *
 * 提供基于 Vue 3 的 Web Component 布局系统：
 * - {@link XUIComponent} — 基类，封装 Shadow DOM 与自定义元素注册。
 * - {@link VUEComponent} — Vue 3 集成组件，继承 XUIComponent。
 * - {@link XUIMeshLayout} — 可拖拽的网格布局编辑器。
 * - {@link XUIMeshDrag} — 拖拽引擎（鼠标拖放 + 拖拽镜像）。
 *
 * Vue 通过全局 `<script>` 标签引入（与 jquery 同方式），
 * 不参与 Vite 打包。
 * 通过npm run build命令编译成layout.xui.js
 */

// ── 外部全局类型声明 ──────────────────────────────────────────────────
// Vue 3 通过 <script> 标签全局引入，通过 window.Vue 访问
declare var Vue: any;

// ── 工具类型 ──────────────────────────────────────────────────────────

/** 网格单元格数据 */
interface MeshCell {
    colspan: number;
    clazz?: string;
    value: string;
    display: string;
    style?: string;
    /** 文本行数，1 为单行 input，>1 为多行 textarea */
    rowCount?: number;
    /** 单元格 UI 类型：undefined/'Widget'=普通组件，'Tablet'=嵌入组件构建器 */
    uiType?: string;
}

/** 网格行（单元格数组） */
type MeshRow = MeshCell[];

/** 单个网格 head 条目 */
interface MeshHeadItem {
    name: string;
    label: string;
    value: string;
}

/** 单个网格定义 */
interface MeshGrid {
    name?: string;
    display?: string;
    en_US?: string;
    zh_CN?: string;
    head: MeshHeadItem[];
    rows: MeshRow[];
    /** "row-col" 格式的当前选中单元格列表 */
    selected?: string[];
}

/** 布局数据结构 */
interface MeshLayout {
    grids: MeshGrid[];
}

// ── XUIComponent ────────────────────────────────────────────────────────

/**
 * Web Component 基类，封装 Shadow DOM 的创建与自定义元素注册。
 *
 * <p>子类通过覆盖 {@code componentTemplate} 提供 HTML/CSS 模板。
 * 构造时自动绑定原型上的所有方法到实例。</p>
 */
export class XUIComponent extends HTMLElement {
    constructor() {
        super();
        this.attachShadow({ mode: 'open' });
        const tmpl = (this.constructor as typeof XUIComponent).componentTemplate;
        if (tmpl) {
            this.shadowRoot!.innerHTML = tmpl;
        }
        // 绑定所有自有方法到当前实例
        const methods = Object.keys(Object.getPrototypeOf(this))
            .filter((key) => key !== 'constructor' && typeof (this as any)[key] === 'function');
        for (const method of methods) {
            const fn = (this as any)[method];
            if (fn) (this as any)[method] = fn.bind(this);
        }
    }

    /** 子类可覆盖以提供 HTML 模板字符串 */
    static get componentTemplate(): string {
        return '';
    }

    /**
     * 注册自定义元素并挂载配置。
     * @param name   自定义元素标签名
     * @param config 挂载到元素实例上的属性/方法
     * @returns 已挂载的元素实例
     */
    static mount(name: string, config?: Record<string, any>): HTMLElement | null {
        const existing = customElements.get(name);
        if (existing === undefined) {
            customElements.define(name, this);
        }
        customElements.whenDefined(name).then(() => {
            // 注册成功
        });
        const el = document.querySelector(name) as HTMLElement;
        if (el && config && typeof config === 'object') {
            for (const key of Object.keys(config)) {
                if (typeof config[key] === 'function') {
                    (el as any)[key] = config[key].bind(el);
                } else {
                    (el as any)[key] = config[key];
                }
            }
        }
        return el;
    }
}

// ── VUEComponent ─────────────────────────────────────────────────────────

/**
 * Vue 3 集成组件，将 Vue 应用挂载到 Shadow DOM 的 {@code <xui-root>} 中。
 *
 * <p>子类通过覆盖 {@code properties}、{@code methods}、{@code vueConfig} 等
 * getter 来提供 Vue 组件的 data、methods 和配置。</p>
 *
 * <p>Vue {@code created} 钩子会将 Vue 方法复制回元素实例上，
 * 使得原生事件回调可以直接调用 Vue 方法。</p>
 */
export class VUEComponent extends XUIComponent {
    /** Vue 3 应用实例 */
    protected vueApp: any;

    constructor() {
        super();

        const that: any = this;
        this.vueApp = Vue.createApp(
            {
                setup(this: any) {
                    typeof that.onSetup === 'function' && that.onSetup(this);
                },
                beforeCreate(this: any) {
                    typeof that.onBeforeCreate === 'function' && that.onBeforeCreate(this);
                },
                created(this: any) {
                    // 绑定 Vue Proxy 的 BoundFunctionObject 到组件实例
                    const methods = Object.keys(this)
                        .filter((key) => typeof this[key] === 'function')
                        .map((key) => this[key]);
                    if (methods) {
                        for (const bounds of methods) {
                            if ((bounds.name as string).startsWith('bound ')) {
                                const funcName = (bounds.name as string).substr(6);
                                if (that[funcName] == undefined) {
                                    that[funcName] = this[funcName];
                                }
                            }
                        }
                    }
                    typeof that.onCreated === 'function' && that.onCreated(this);
                },
                mounted(this: any) {
                    typeof that.onSuccess === 'function' && that.onSuccess(this);
                },
                data(this: any) {
                    if (that.properties === undefined) {
                        return { self: that };
                    }
                    return that.properties;
                },
                methods: that.methods === undefined ? {} : that.methods,
                ...(that.setting === undefined ? {} : that.setting),
            },
            this.vueConfig,
        );

        const xwxRoot = this.shadowRoot!.querySelector('xui-root');
        if (xwxRoot) {
            this.vueApp.mount(xwxRoot);
        } else {
            console.error('XWX Component must take <xui-root> as root element.');
        }
    }

    /** 子类可覆盖以提供 Vue data 对象 */
    protected get properties(): Record<string, any> {
        return {};
    }

    /** 子类可覆盖以提供 Vue methods */
    protected get methods(): Record<string, any> {
        return {};
    }

    /** Vue 应用的全局配置选项 */
    protected get vueConfig(): Record<string, any> {
        return {
            compilerOptions: {
                isCustomElement: (tag: string) => tag.startsWith('xui-'),
            },
        };
    }

    /** Vue 应用的根组件选项（与 vueConfig 合并） */
    protected get setting(): Record<string, any> {
        return { shadowRoot: true };
    }

    /** 返回 Vue 3 应用实例 */
    getVueApp(): any {
        return this.vueApp;
    }
}

// ── XUIMeshDrag ──────────────────────────────────────────────────────────

/** 拖拽引擎配置 */
interface MeshDragConfig {
    /** 从鼠标事件中提取拖拽数据 */
    pickPallet?: (event: MouseEvent) => any;
    /** 拖拽放置时的回调 */
    placeDragging?: (event: MouseEvent) => void;
}

/**
 * 拖拽引擎，通过跟踪鼠标事件实现自定义拖拽效果。
 *
 * <p>创建一个绝对定位的 sharp 元素作为拖拽镜像，
 * 通过 {@code mousedown} / {@code mousemove} / {@code mouseup}
 * 事件控制拖拽生命周期。</p>
 *
 * <p>外部使用者通过设置 {@code pickPallet} 和 {@code placeDragging}
 * 回调来控制拖拽数据和放置行为。</p>
 */
export class XUIMeshDrag {
    /** 当前拖拽携带的数据 */
    private pallet: any = {};
    /** 是否正在拖拽中 */
    private movable: boolean = false;
    /** 鼠标相对幽灵元素的偏移 */
    private offset = { x: 0, y: 0 };
    /** 拖拽幽灵元素 */
    private sharp: HTMLElement;

    /** 拖拽放置回调 */
    placeDragging: ((event: MouseEvent) => void) | undefined;

    /**
     * 构造拖拽引擎，创建幽灵元素并添加到 document.body。
     * @param config 可选配置
     */
    constructor(config?: MeshDragConfig) {
        if (config) {
            Object.assign(this, config);
        }
        this.sharp = document.createElement('div');
        this.sharp.style.cursor = 'hand';
        this.sharp.style.position = 'absolute';
        this.sharp.style.fontSize = '12px';
        this.sharp.style.border = '1px solid whitesmoke';
        this.sharp.style.backgroundColor = '#78c6eb';
        this.sharp.style.display = 'none';
        this.sharp.style.padding = '2px';
        this.sharp.onselectstart = () => false;
        document.body.appendChild(this.sharp);
    }

    /** 获取当前拖拽承载的数据 */
    getPallet(): any {
        return this.pallet;
    }

    /**
     * 从事件中提取拖拽数据，子类可覆盖。
     * @returns 拖拽数据对象，返回 undefined 不会开始拖拽
     */
    pickPallet(_event: MouseEvent): any {
        return undefined;
    }

    /**
     * 开始拖拽。调用 {@code pickPallet} 提取数据并显示幽灵元素。
     *
     * <p>幽灵元素显示在事件目标附近，带有彩色渐变背景。
     * 设置 {@code movable = true} 后，后续的 mousemove/mouseup 事件才会响应。</p>
     */
    onDraggingStart(event: MouseEvent): void {
        this.pallet = this.pickPallet(event);
        if (this.pallet) {
            const pos = this.getPosition((event.target as HTMLElement)?.parentNode as HTMLElement);
            this.sharp.style.display = 'block';
            this.sharp.style.left = pos.x + 'px';
            this.sharp.style.top = pos.y + 'px';
            this.sharp.style.minWidth = '135px';
            this.sharp.style.height = '22px';
            this.sharp.style.background =
                'linear-gradient(90deg,rgba(220,137,255,1)0%,rgba(162,152,255,1)52%,rgba(83,160,253,1)100%)';
            if (this.pallet.display) {
                this.sharp.innerHTML = this.pallet.display;
                this.sharp.setAttribute('name', this.pallet.id + '~' + this.pallet.name);
            } else {
                this.sharp.innerHTML = this.pallet.name;
                this.sharp.setAttribute('name', this.pallet.id + '~' + this.pallet.name);
            }
            this.offset.x = event.clientX - pos.x;
            this.offset.y = event.clientY - pos.y;
            this.movable = true;
        }
    }

    /**
     * 拖拽移动。根据鼠标位置更新幽灵元素的 top/left。
     * 同时高亮鼠标下方的 {@code td.cell} 元素。
     */
    onDraggingMove(event: MouseEvent): void {
        if (!this.movable) return;

        this.sharp.style.top = event.clientY - this.offset.y + 'px';
        this.sharp.style.left = event.clientX - this.offset.x + 2 + 'px';
        const elements = document.querySelectorAll('td:hover');
        for (const td of elements) {
            if (td && td.classList.contains('cell')) {
                (td as HTMLElement).style.backgroundColor = '#ffccff';
            }
        }
    }

    /**
     * 拖拽放置。隐藏幽灵元素，设置 {@code movable = false}，
     * 并调用 {@code placeDragging} 回调完成数据写入。
     */
    onDraggingPlace(event: MouseEvent): void {
        if (this.movable) {
            this.movable = false;
            this.sharp.style.display = 'none';
            if (typeof this.placeDragging === 'function') {
                this.placeDragging(event);
            }
        }
    }

    /**
     * 获取目标元素的绝对坐标。
     * @param el 目标 DOM 元素
     * @returns 绝对像素偏移
     */
    getPosition(el: HTMLElement | null): { x: number; y: number } {
        if (!el) return { x: 0, y: 0 };

        let curLeft = 0;
        let curTop = 0;
        if (el.offsetParent) {
            while (el.offsetParent) {
                curLeft += el.offsetLeft;
                curTop += el.offsetTop;
                el = el.offsetParent as HTMLElement;
            }
        } else if ((el as any).x) {
            curLeft += (el as any).x;
        } else if ((el as any).y) {
            curTop += (el as any).y;
        }

        return { x: curLeft, y: curTop };
    }
}

// ── XUIMeshLayout ────────────────────────────────────────────────────────

/**
 * 可拖拽的网格布局编辑器。
 *
 * <p>内部嵌入一个 Vue 3 表格组件，支持：</p>
 * <ul>
 *   <li>从属性表格拖入属性到 Cell 中（通过 XUIMeshDrag 引擎）</li>
 *   <li>Cell 间拖拽移动数据（HTML5 Drag & Drop）</li>
 *   <li>行内 Cell 合并/拆分（通过 mergeSplit）</li>
 *   <li>行交换（angleUp/Down）和 Cell 交换（angleLeft/Right）</li>
 *   <li>Cell 样式编辑（editStyle 弹出窗口）</li>
 *   <li>行增删（addLayoutRow / delLayoutRow）</li>
 * </ul>
 */
export class XUIMeshLayout extends VUEComponent {

    /** 拖拽引擎实例 */
    private meshDrag: XUIMeshDrag;

    static get observedAttributes(): string[] {
        return [];
    }

    constructor() {
        super();
        this.meshDrag = new XUIMeshDrag();

        /**
         * 拖拽放置回调：通过 shadowRoot.elementFromPoint 定位目标 Cell，
         * 将 pallet 中的数据写入 Cell 的 value/display 字段。
         *
         * <p>使用 elementFromPoint 而非 :hover 选择器，确保准确定位。
         * sharp 幽灵元素在 onDraggingPlace 中已隐藏，不会阻挡坐标查找。</p>
         */
        this.meshDrag.placeDragging = (event: MouseEvent) => {
            const pallet = this.meshDrag.getPallet();
            if (!pallet) return;

            const target = this.shadowRoot!.elementFromPoint(event.clientX, event.clientY);
            if (!target) return;
            const span = target.classList.contains('cell') ? target : target.closest('span.cell');
            if (!span) return;

            const idx = span.getAttribute('idx');
            const row = span.getAttribute('row');
            const col = span.getAttribute('col');
            const grid = (this as any).getGrid(idx!);
            if (!grid) return;

            // 检查该属性在当前 grid 中是否已存在，避免重复拖入
            const exists = grid.rows.some((r: MeshRow) =>
                Object.keys(r).some((k: string) => (r as any)[k] !== undefined && (r as any)[k].value === pallet.name),
            );
            if (exists) return;

            const targetRow = grid.rows[parseInt(row!)];
            if (!targetRow) return;
            const cell = (targetRow as any)[col!] as MeshCell;
            if (!cell) return;
            cell.value = pallet.name;
            cell.display = pallet.display;
        };
    }

    /** 组件模板：Shadow DOM 内的 <style> + Vue 模板 */
    static get componentTemplate(): string {
        return `<style>
	:host{position:relative;display:inline-block}
    .meshLayout{font-size:12px;border:1px solid lightgrey;border-radius:5px;border-spacing:0px;border-collapse:separate;}
    .meshLayout span.focus{background-color:blanchedalmond;}
    .meshLayout span.selected{background-color:#b3d9ff;box-shadow:inset 0 0 0 2px #1a73e8;}
    .meshLayout span:hover{background-color:blanchedalmond;}
    .meshLayout span.cell{display:block;padding-left:2px;width:100%;height:20px;}
    .meshLayout td{height:20px;font-size:12px;padding-left:2px;border-bottom:1px solid lightgrey;border-right:1px solid lightgrey;cursor:default;}
    .meshLayout tbody tr{display:flex;}
    .meshLayout .col-slot{flex:1;min-width:80px;}
    .meshLayout .row-num{width:24px;flex:none;}
    .meshLayout .row-tools{width:36px;flex:none;}
    .meshLayout .row-tools button{width:14px;height:18px;padding:0;text-align:center;line-height:16px;border:1px solid lightgrey;border-radius:3px;background-color:aliceblue;}
    .meshLayout .row-tools button:hover{border:1px solid #03638d;}
    .meshLayout .toolbar .tool-btn{width:16px;height:16px;vertical-align:middle;cursor:pointer;border:1px solid #ccc;border-radius:3px;padding:2px;background:aliceblue;}
    .meshLayout .toolbar .tool-btn:hover{border:1px solid #03638d;}
    .meshLayout .toolbar{background-color:#80cefc;border-bottom:1px solid lightgrey !important;}
    .meshLayout th{font-size:12px;font-weight:normal;border-bottom:2px solid black;background-color:#80cefc;padding:2px 4px;}
</style>${XUIMeshLayout.TEMPLATE}`;
    }

    /**
     * Vue 模板（Vue compile 时编译为 render 函数）。
     *
     * <p>模板结构：</p>
     * <ul>
     *   <li>{@code <xui-root>} — Vue 挂载根节点</li>
     *   <li>{@code v-for="grid in layout.grids"} — 遍历所有 Grid，每个 Grid 渲染为一个表格</li>
     *   <li>thead 工具栏 — 上/下/左/右移动、合并/拆分、编辑样式、删除 Grid</li>
     *   <li>tbody 单元格区域 — 4 列布局，支持拖拽、点选、colspan 合并</li>
     *   <li>底部 "新增 Grid" 按钮</li>
     * </ul>
     *
     * <p>每个 Cell 渲染为 flex 布局：左侧显示 display，右侧灰色显示 uiType。</p>
     */
    private static readonly TEMPLATE = /* html */`
<xui-root>
    <div :title="grid.display" v-for="(grid, idx) in layout.grids" style="display:flex;justify-content:space-between;margin-bottom:5px;">
        <span style="flex:1;margin-right:10px;">
            <table class="meshLayout" :id="'meshLayout-'+grid.name" name="meshLayoutInfo" style="width:100%;">
                <thead style="display:table;width:100%;table-layout:fixed;">
                    <!-- ===== 表头：Grid 元信息 + 工具栏 ===== -->
                    <tr>
                        <th style="display:flex;align-items:center;">
                            <span v-for="(row, index) in grid.head" style="margin-left:20px;">
                                <label style="font-weight:bold;">{{row.label}}</label>
                                <span>{{row.value}}</span>
                            </span>
                            <!-- 工具栏按钮组：编辑样式、合并/拆分、上下左右移动、删除 Grid -->
                            <span class="toolbar" style="font-size:18px;display:flex;align-items:center;margin-left:auto;">
                                <img src="images/svg/build.svg" :alt="i18n.editCell || 'Edit Cell'" @click="editStyle(idx);" class="tool-btn">
                                <img src="images/svg/mixer.svg" :alt="i18n.mergeSplit || 'Merge/Split'" @click="mergeSplit(idx);" class="tool-btn">
                                <img src="images/svg/arrow-up.svg" :alt="i18n.moveUp || 'Move Up'" @click="angleUp(idx);" class="tool-btn">
                                <img src="images/svg/arrow-down.svg" :alt="i18n.moveDown || 'Move Down'" @click="angleDown(idx);" class="tool-btn">
                                <img src="images/svg/arrow-back.svg" :alt="i18n.moveLeft || 'Move Left'" @click="angleLeft(idx);" class="tool-btn">
                                <img src="images/svg/arrow-forward.svg" :alt="i18n.moveRight || 'Move Right'" @click="angleRight(idx);" class="tool-btn">
                                <img v-if="idx > 0" src="images/svg/close.svg" :alt="i18n.delete || 'Delete'" @click="angleClose(idx);" class="tool-btn">
                            </span>
                        </th>
                    </tr>
                </thead>
                <!-- ===== 表体：可拖拽的单元格网格（4 列 × N 行） ===== -->
                <tbody style="display:block;overflow-y:scroll;height:206px;">
                    <tr v-for="(row, index) in grid.rows" :key="index" style="display:table;width:100%;table-layout:fixed;">
                        <!-- 行号列 -->
                        <td class="row-num" style="text-align:center;background:aliceblue">{{index}}</td>
                        <!-- 4 列单元格：colspan>1 的单元格会覆盖相邻列，覆被盖列由 isCellCovered 跳过 -->
                        <template v-for="col in [0,1,2,3]" :key="col">
                            <td class="col-slot" v-if="!isCellCovered(idx, index, col)" :colspan="row[col].colspan" @dragover.prevent @drop="onCellDrop($event, idx, index, col)">
                                <!-- Cell：flex 布局，display 靠左 + uiType 灰色靠右 -->
                                <span class="cell" :class="{ selected: isSelected(idx, index, col) }" draggable="true" :idx="idx" :row="index" :col="col" :field="row[col].value"
                                    @click="toggleSelect(idx, index, col)" @dragstart="onCellDragStart($event, idx, index, col)" @dragend="onCellDragEnd($event, idx, index, col)" style="display:flex;justify-content:space-between;align-items:center;">
                                    <span>{{row[col].display}}</span> <span v-if="row[col].display" style="color:#C5C5C5;font-size:9px;margin-right:2px">{{row[col].uiType}}</span>
                                </span>
                            </td>
                        </template>
                        <!-- 行操作按钮：删除（首行不显示）、新增 -->
                        <td class="row-tools">
                            <button type="button" @click="delLayoutRow(idx+'-'+index)" v-if="index>0">-</button>
                            <button type="button" @click="addLayoutRow(idx+'-'+index)">+</button>
                        </td>
                    </tr>
                </tbody>
            </table>
        </span>
    </div>
    <!-- 底部：新增 Grid 按钮 -->
    <div style="display:flex;justify-content:center;margin-top:8px;">
        <img src="images/svg/add.svg" alt="新增Grid" @click="addGrid();" class="tool-btn" style="width:20px;height:20px;cursor:pointer;">
    </div>
</xui-root>`;

    // ── Vue data ───────────────────────────────────────────────────────

    /**
     * Vue 组件的 data 对象。
     *
     * <ul>
     *   <li>{@code layout} — 布局数据，初始为含一个空 grid 的结构</li>
     *   <li>{@code cellSelection} — 选中状态映射，key 为 "idx-row-col" 格式</li>
     * </ul>
     */
    protected get properties(): Record<string, any> {
        const that = this;

        return {
            /** Vue 组件自身引用，供模板内访问 */
            self: that,
            /** XUIMeshDrag 拖拽进行中标记 */
            movable: false,
            /** 拖拽幽灵元素的引用（保留字段） */
            movedDiv: null,
            /** 网格表格的 jQuery 对象缓存，see getMeshLayout() */
            meshLayout: null,
            /** 属性 ID → 属性对象映射（getPropertyRow 填充） */
            propertyMap: new Map(),
            /** 布局数据（响应式），所有 Grid 操作直接修改此对象 */
            layout: {
                grids: [{
                    head: [] as MeshHeadItem[],
                    rows: [] as MeshRow[],
                }],
            } as MeshLayout,
            /** 选中状态映射，key 为 "idx-row-col" 格式 */
            cellSelection: {} as Record<string, boolean>,
            /** 多语言文本，由页面全局 i18n 变量注入 */
            i18n: (window as any).i18n || {},
        };
    }

    // ── Vue methods ────────────────────────────────────────────────────

    /**
     * Vue 组件的 methods 对象。
     *
     * <p>所有方法在 Vue {@code created} 钩子中自动复制到 XUIMeshLayout
     * 元素实例上，使原生事件回调可直接调用。</p>
     */
    protected get methods(): Record<string, any> {
        const that = this;
        return {

            /**
             * 从外部加载布局数据，替换当前 layout。
             * @param data MeshLayout JSON 数据
             */
            loadLayoutTable(this: any, data: any) {
                if (data) {
                    this.layout = data;
                }
            },

            /**
             * 保存布局编辑结果，触发 {@code onSaveLayout} 回调。
             */
            saveLayoutEdit(this: any) {
                const json = JSON.stringify(this.layout);
                typeof (that as any).onSaveLayout === 'function' && (that as any).onSaveLayout(JSON.parse(json));
            },

            /**
             * 设置指定 Cell 的 value 和 display。
             * @param id    "idx-row-col" 格式的 Cell 标识
             * @param value 要设置的值
             */
            setGridCellValue(this: any, id: string, value: string) {
                if (!id) return;
                const array = id.split('-');
                const grid = this.getGrid(array[0]);
                if (grid) {
                    const row = grid.rows[array[1]];
                    if (row) {
                        const cell = row[parseInt(array[2])];
                        cell.value = value;
                        cell.display = value;
                    }
                }
            },

            /**
             * 清除网格表格中所有 td.cell 的背景色和光标样式。
             */
            cleanBackColor(this: any) {
                const $tds = this.getMeshLayout().find('td.cell');
                for (const $td of $tds) {
                    $td.style.backgroundColor = null;
                    $td.style.cursor = null;
                }
            },

            /**
             * 从 EasyUI datagrid 的行中提取属性信息。
             *
             * <p>读取 oid、display、name 并存入 propertyMap。</p>
             * @param el datagrid-cell 元素
             * @returns 属性对象 { oid, display, name }
             */
            getPropertyRow(this: any, el: HTMLElement) {
                if (!that.isDom(el)) return;

                let tr: HTMLElement | null = null;
                if (el.classList.contains('datagrid-cell')) {
                    tr = el.parentNode?.parentNode as HTMLElement;
                }
                if (tr) {
                    const childs = tr.childNodes;
                    const property = {
                        oid: (childs[0] as HTMLElement).innerText,
                        display: (childs[1] as HTMLElement).innerText,
                        name: (childs[2] as HTMLElement).innerText,
                    };
                    this.propertyMap.set(property.oid, property);
                    return property;
                }
            },

            /**
             * 保留方法：判断元素是否为网格布局表格。
             * <p>当前为桩实现，始终返回 null，供外部扩展覆盖。</p>
             */
            isMeshLayout(_el: HTMLElement) {
                return null;
            },

            /**
             * 获取网格布局表格的 jQuery 对象（懒加载）。
             */
            getMeshLayout(this: any) {
                if (this.meshLayout == null) {
                    this.meshLayout = jQuery("table[name='meshLayout']") as any;
                }
                return this.meshLayout;
            },

            /**
             * 删除指定索引的行。
             * @param index "idx-row" 格式，例如 "0-3"
             */
            delLayoutRow(this: any, index: string) {
                if (index) {
                    const array = index.split('-');
                    const grid = this.getGrid(array[0]);
                    if (grid) {
                        grid.rows.splice(parseInt(array[1]), 1);
                    }
                }
            },

            /**
             * 在指定位置下方插入一个空行。
             * @param index "idx-row" 格式，在 row+1 位置插入
             */
            addLayoutRow(this: any, index: string) {
                if (index) {
                    const array = index.split('-');
                    const grid = this.getGrid(array[0]);
                    if (grid) {
                        grid.rows.splice(parseInt(array[1]) + 1, 0, [
                            { colspan: 1, clazz: '', style: '', rowCount: 1, value: '', display: '' },
                            { colspan: 1, clazz: '', style: '', rowCount: 1, value: '', display: '' },
                            { colspan: 1, clazz: '', style: '', rowCount: 1, value: '', display: '' },
                            { colspan: 1, clazz: '', style: '', rowCount: 1, value: '', display: '' },
                        ]);
                    }
                }
            },

            /**
             * 打开 Cell 编辑弹窗。
             *
             * <p>弹窗包含：</p>
             * <ul>
             *   <li>Tablet 类名 — 设置后 cell.uiType 为 Tablet</li>
             *   <li>CSS 样式 — 写入 cell.style</li>
             *   <li>行数 — 写入 cell.rowCount（1=单行 input，>1=多行 textarea）</li>
             * </ul>
             *
             * <p>使用 {@code grid.selected} 定位当前 Cell。</p>
             *
             * @param index grid 索引
             */
            editStyle(this: any, index: number) {
                const grid = this.getGrid(index);
                if (!grid) return;

                if (!grid.selected?.length) { alert('未选中任何单元格'); return; }
                const [hRow, hCol] = grid.selected[0].split('-').map(Number);
                const cell = grid.rows[hRow]?.[hCol];
                if (!cell) return;

                const cellWin = document.createElement('x-window');
                cellWin.id = 'xui-cell-dlg';
                cellWin.title = '编辑单元格';
                cellWin.setAttribute('x-options', "park:'center',minimize:false,maximize:false,resize:false,destroy:true");
                cellWin.style.cssText = 'width:420px;height:360px';
                cellWin.content(`
                    <div style="padding:12px 16px 16px;">
                        <label style="font-size:13px;color:#555;display:block;">Cell 类型：</label>
                        <select id="xui-uitype-select" onchange="((el)=>{
                            const ri=el.querySelector('#xui-rows-input');
                            ri.disabled=this.value==='Widget';
                            if(this.value==='Widget') {
                                ri.value=1;
                            }
                        })(this.closest('div'))" style="width:100%;height:28px;margin-top:4px;padding:4px 8px;border:1px solid #ccc;border-radius:3px;box-sizing:border-box;">
                            <option value="Widget" ${cell.uiType !== 'Tablet' ? 'selected' : ''}>Widget</option>
                            <option value="Tablet" ${cell.uiType === 'Tablet' ? 'selected' : ''}>Tablet</option>
                        </select>
                        <label style="font-size:13px;color:#555;display:block;margin-top:10px;">Cell 内容（属性名 或 表格类名）：</label>
                        <input id="xui-value-input" value="${cell.value || ''}" placeholder="属性字段名 或 xw.auths.builder.GroupListTableBuilder" style="width:100%;height:28px;margin-top:4px;padding:4px 8px;border:1px solid #ccc;border-radius:3px;box-sizing:border-box;"/>
                        <label style="font-size:13px;color:#555;display:block;margin-top:10px;">CSS 样式（应用到单元格）：</label>
                        <input id="xui-style-input" value="${cell.style || ''}" placeholder="color:red;font-weight:bold;" style="width:100%;height:28px;margin-top:4px;padding:4px 8px;border:1px solid #ccc;border-radius:3px;box-sizing:border-box;"/>
                        <label style="font-size:13px;color:#555;display:block;margin-top:10px;">行数设置（1: 单行input，>1: 多行textarea）：</label>
                        <input id="xui-rows-input" type="number" min="1" value="${cell.rowCount || 1}" ${cell.uiType == 'Tablet' ? 'disabled' : ''} style="width:100%;height:28px;margin-top:4px;padding:4px 8px;border:1px solid #ccc;border-radius:3px;box-sizing:border-box;"/>
                        <div style="display:flex;justify-content:flex-end;gap:8px;margin-top:14px;">
                            <button style="padding:6px 18px;border:1px solid #ccc;border-radius:3px;background:#f5f5f5;cursor:pointer;" onclick="this.closest('x-window')?.close()">取消</button>
                            <button style="padding:6px 18px;border:1px solid #03638d;border-radius:3px;background:#03638d;color:#fff;cursor:pointer;" onclick="
                                (function(el){
                                    const w=el.closest('x-window');
                                    const us=w.querySelector('#xui-uitype-select');
                                    const vi=w.querySelector('#xui-value-input');
                                    const si=w.querySelector('#xui-style-input');
                                    const ri=w.querySelector('#xui-rows-input');
                                    const val=vi.value.trim(), d=w.data;
                                    d.cell.value=val||'';
                                    if(us.value === 'Tablet'){
                                        d.cell.display=val.substring(val.lastIndexOf('.')+1)||val;
                                        d.cell.uiType='Tablet';
                                    }else{
                                        d.cell.display=val||'';
                                        d.cell.uiType=undefined;
                                    }
                                    d.cell.style=si.value.trim()||null;
                                    d.cell.rowCount=parseInt(ri.value)||1;
                                    const row=d.grid.rows[d.hRow];
                                    if(row) row[d.hCol]=d.cell;
                                    w.close();
                                })(this)
                            ">确认</button>
                        </div>
                    </div>`, { cell, grid, hRow, hCol });
                cellWin.open();
            },

            /**
             * 打开新增 Grid 弹窗。
             *
             * <p>以 {@code grids[0]} 为模板，深拷贝后清除数据，
             * 弹窗字段由 {@code grids[0].head} 动态生成。</p>
             */
            addGrid(this: any) {
                const template = this.layout.grids[0];
                if (!template) { alert('暂无参考 Grid'); return; }

                // 深拷贝模板并清除所有数据
                const clone = JSON.parse(JSON.stringify(template));
                for (const h of clone.head) {
                    h.value = '';
                    if (Object.prototype.hasOwnProperty.call(clone, h.name)) clone[h.name] = '';
                }
                for (const row of clone.rows) {
                    for (const cell of row) {
                        cell.value = '';
                        cell.display = '';
                    }
                }

                // 根据模板 head 动态生成输入字段
                let fieldsHtml = '';
                for (let i = 0; i < template.head.length; i++) {
                    const h = template.head[i];
                    fieldsHtml += `
                        <label style="font-size:13px;color:#555;display:block;margin-top:${i === 0 ? '0' : '10px'};">${h.label}</label>
                        <input id="xui-grid-${h.name}" style="width:100%;height:28px;margin-top:4px;padding:4px 8px;border:1px solid #ccc;border-radius:3px;box-sizing:border-box;"/>`;
                }

                const gridWin = document.createElement('x-window');
                gridWin.id = 'xui-add-grid-dlg';
                gridWin.title = '新增 Grid';
                gridWin.setAttribute('x-options', "park:'center',minimize:false,maximize:false,resize:false,destroy:true");
                gridWin.style.cssText = `width:400px;height:360px`;
                gridWin.content(`
                    <div style="padding:12px 16px 16px;">
                        ${fieldsHtml}
                        <div style="display:flex;justify-content:flex-end;gap:8px;margin-top:12px;">
                            <button style="padding:6px 18px;border:1px solid #ccc;border-radius:3px;background:#f5f5f5;cursor:pointer;" onclick="this.closest('x-window')?.close()">取消</button>
                            <button style="padding:6px 18px;border:1px solid #03638d;border-radius:3px;background:#03638d;color:#fff;cursor:pointer;" onclick="
                                (function(el){
                                    const w=el.closest('x-window'),d=w.data;
                                    const clone=d.clone;
                                    for(const h of clone.head){
                                        const input=w.querySelector('#xui-grid-'+h.name);
                                        if(input) h.value=input.value.trim();
                                        if(Object.prototype.hasOwnProperty.call(clone, h.name)) clone[h.name]=h.value;
                                    }
                                    d.self.layout.grids.push(clone);
                                    w.close();
                                })(this)
                            ">确认</button>
                        </div>
                    </div>`, { self: this, clone });
                gridWin.open();
            },

            /**
             * 将选中行与上一行交换数据，选择跟随移动到上一行。
             * @param index grid 索引
             */
            angleUp(this: any, index: number) {
                const grid = this.getGrid(index);
                const pos = grid?.selected?.[0];
                if (grid && pos) {
                    const value = this.getCell(index, pos);
                    const array = pos.split('-');
                    const row = parseInt(array[0]), col = parseInt(array[1]);
                    const up = row - 1;
                    if (up > -1) {
                        const uIndex = up + '-' + col;
                        const uValue = this.getCell(index, uIndex);
                        this.setCell(index, pos, uValue);
                        this.setCell(index, uIndex, value);
                        this.cellSelection[index + '-' + row + '-' + col] = false;
                        this.cellSelection[index + '-' + up + '-' + col] = true;
                        grid.selected[0] = uIndex;
                    }
                }
            },

            /**
             * 将选中行与下一行交换数据，选择跟随移动到下一行。
             * @param index grid 索引
             */
            angleDown(this: any, index: number) {
                const grid = this.getGrid(index);
                const pos = grid?.selected?.[0];
                if (grid && pos) {
                    const value = this.getCell(index, pos);
                    const array = pos.split('-');
                    const row = parseInt(array[0]), col = parseInt(array[1]);
                    const down = row + 1;
                    if (down > -1) {
                        const dIndex = down + '-' + col;
                        const dValue = this.getCell(index, dIndex);
                        this.setCell(index, pos, dValue);
                        this.setCell(index, dIndex, value);
                        this.cellSelection[index + '-' + row + '-' + col] = false;
                        this.cellSelection[index + '-' + down + '-' + col] = true;
                        grid.selected[0] = dIndex;
                    }
                }
            },

            /**
             * 将选中列与左边一列交换数据，选择跟随移动到左边。
             * @param index grid 索引
             */
            angleLeft(this: any, index: number) {
                const grid = this.getGrid(index);
                const pos = grid?.selected?.[0];
                if (grid && pos) {
                    const value = this.getCell(index, pos);
                    const array = pos.split('-');
                    const row = parseInt(array[0]), col = parseInt(array[1]);
                    const left = col - 1;
                    if (left > -1) {
                        const lIndex = row + '-' + left;
                        const lValue = this.getCell(index, lIndex);
                        this.setCell(index, pos, lValue);
                        this.setCell(index, lIndex, value);
                        this.cellSelection[index + '-' + row + '-' + col] = false;
                        this.cellSelection[index + '-' + row + '-' + left] = true;
                        grid.selected[0] = lIndex;
                    }
                }
            },

            /**
             * 将选中列与右边一列交换数据，选择跟随移动到右边。
             * @param index grid 索引
             */
            angleRight(this: any, index: number) {
                const grid = this.getGrid(index);
                const pos = grid?.selected?.[0];
                if (grid && pos) {
                    const value = this.getCell(index, pos);
                    const array = pos.split('-');
                    const row = parseInt(array[0]), col = parseInt(array[1]);
                    const right = col + 1;
                    if (right < 4) {
                        const rIndex = row + '-' + right;
                        const rValue = this.getCell(index, rIndex);
                        this.setCell(index, pos, rValue);
                        this.setCell(index, rIndex, value);
                        this.cellSelection[index + '-' + row + '-' + col] = false;
                        this.cellSelection[index + '-' + row + '-' + right] = true;
                        grid.selected[0] = rIndex;
                    }
                }
            },

            /**
             * 删除当前 Grid。
             * @param index grid 索引
             */
            angleClose(this: any, index: number) {
                this.layout.grids.splice(index, 1);
            },

            /**
             * 切换 Cell 的选中状态。
             *
             * <p>选中某个 Cell 时，自动取消同 grid 内其他行的所有选中，
             * 确保同一时刻只有一个行的 Cell 被选中。</p>
             *
             * @param idx grid 索引
             * @param row 行号
             * @param col 列号 (0-3)
             */
            toggleSelect(this: any, idx: number, row: number, col: number) {
                const key = idx + '-' + row + '-' + col;
                const grid = this.getGrid(idx);
                const rc = row + '-' + col;
                if (this.cellSelection[key]) {
                    this.cellSelection[key] = false;
                    if (grid?.selected) {
                        grid.selected = grid.selected.filter(s => s !== rc);
                    }
                } else {
                    for (const k of Object.keys(this.cellSelection)) {
                        if (k.startsWith(idx + '-') && k.split('-')[1] !== String(row)) {
                            this.cellSelection[k] = false;
                            if (grid?.selected) {
                                const old = k.split('-').slice(1).join('-');
                                grid.selected = grid.selected.filter(s => s !== old);
                            }
                        }
                    }
                    this.cellSelection[key] = true;
                    if (grid) {
                        if (!grid.selected) grid.selected = [];
                        if (!grid.selected.includes(rc)) grid.selected.push(rc);
                    }
                }
            },

            /**
             * 判断指定 Cell 是否被选中。
             * @returns 选中状态
             */
            isSelected(this: any, idx: number, row: number, col: number): boolean {
                return !!this.cellSelection[idx + '-' + row + '-' + col];
            },

            /**
             * 判断指定位置是否被 colspan 覆盖（被合并的 Cell 不渲染）。
             *
             * <p>当 col 位置被前面单元格的 colspan 覆盖，或当前 Cell
             * 的 colspan 为 0 时返回 true。</p>
             *
             * @param idx grid 索引
             * @param row 行号
             * @param col 列号
             * @returns 是否被覆盖
             */
            isCellCovered(this: any, idx: number, row: number, col: number): boolean {
                const grid = this.getGrid(idx);
                if (!grid || !grid.rows[row]) return false;
                if (grid.rows[row][col].colspan === 0) return true;
                for (let c = 0; c < col; c++) {
                    if (c + grid.rows[row][c].colspan > col) return true;
                }
                return false;
            },

            /**
             * 根据选中 Cell 的个数和 colspan 自动决定合并或拆分。
             *
             * <ul>
             *   <li>同行选中 ≥2 个 Cell → 合并为一个，colspan 累加，
             *       被合并的 Cell 的 colspan 置为 0 并清空显示。</li>
             *   <li>单个 Cell 且 colspan > 1 → 拆分，colspan 减 1。</li>
             * </ul>
             *
             * @param index grid 索引
             */
            mergeSplit(this: any, index: number) {
                const grid = this.getGrid(index);
                if (!grid) return;

                const pos = grid.selected?.[0];
                if (!pos) return;
                const [hRow, hCol] = pos.split('-').map(Number);
                const cell = grid.rows[hRow]?.[hCol];

                const selectedCols = (grid.selected || [])
                    .filter(s => s.startsWith(hRow + '-'))
                    .map(s => parseInt(s.split('-')[1]))
                    .sort((a, b) => a - b);

                if (selectedCols.length >= 2) {
                    let total = 0;
                    for (const c of selectedCols) total += grid.rows[hRow][c].colspan;
                    grid.rows[hRow][selectedCols[0]].colspan = total;
                    for (let i = 1; i < selectedCols.length; i++) {
                        const c = selectedCols[i];
                        const mc = grid.rows[hRow][c];
                        mc.colspan = 0;
                        mc.value = '';
                        mc.display = '';
                        this.cellSelection[index + '-' + hRow + '-' + c] = false;
                        if (grid.selected) grid.selected = grid.selected.filter(s => s !== hRow + '-' + c);
                    }
                    this.cellSelection[index + '-' + hRow + '-' + selectedCols[0]] = false;
                    if (grid.selected) grid.selected = grid.selected.filter(s => s !== hRow + '-' + selectedCols[0]);
                } else if (cell && cell.colspan > 1) {
                    cell.colspan -= 1;
                }
            },

            // ── 数据访问：Grid / Cell 读写 ──────────────────────────────

            /**
             * 获取指定 grid 的数据。
             * @param index grid 索引
             */
            getGrid(this: any, index: number): MeshGrid | undefined {
                return this.layout.grids[index];
            },

            /**
             * 获取指定位置的 Cell 数据。
             * @param idx   grid 索引
             * @param index "row-col" 格式
             */
            getCell(this: any, idx: number, index: string): MeshCell | undefined {
                const grid = this.getGrid(idx);
                if (grid) {
                    const array = index.split('-');
                    const row = grid.rows[array[0]];
                    if (row) {
                        return row[parseInt(array[1])];
                    }
                }
                return undefined;
            },

            /**
             * 设置指定位置的 Cell 数据。
             * @param idx   grid 索引
             * @param index "row-col" 格式
             * @param val   新 Cell 数据
             */
            setCell(this: any, idx: number, index: string, val: MeshCell) {
                const grid = this.getGrid(idx);
                if (grid) {
                    const array = index.split('-');
                    const row = grid.rows[array[0]];
                    if (row) {
                        (row as any)[array[1]] = val;
                    }
                }
            },

            // ── 拖拽操作：Cell 间 HTML5 Drag & Drop ─────────────────────

            /**
             * Cell 拖拽开始（HTML5 Drag & Drop，Cell 间移动）。
             *
             * <p>只有有 value 的 Cell 才能被拖拽。
             * 将源位置信息以 JSON 存入 dataTransfer。</p>
             */
            onCellDragStart(this: any, event: DragEvent, _idx: number, row: number, col: number) {
                const cell = this.getCell(_idx, row + '-' + col);
                if (!cell || !cell.value) {
                    event.preventDefault();
                    return;
                }
                event.dataTransfer!.setData('text/plain', JSON.stringify({ idx: _idx, row, col }));
                event.dataTransfer!.effectAllowed = 'move';
            },

            /**
             * Cell 拖拽放置（HTML5 Drag & Drop，Cell 间移动）。
             *
             * <p>从 dataTransfer 读取源位置，将源 Cell 的 value/display
             * 写入目标 Cell，并清空源 Cell。会检测目标 grid 中是否已存在同名属性。</p>
             */
            onCellDrop(this: any, event: DragEvent, idx: number, row: number, col: number) {
                event.preventDefault();
                const raw = event.dataTransfer!.getData('text/plain');
                if (!raw) return;
                const data = JSON.parse(raw);
                if (data.idx === idx && data.row === row && data.col === col) return;

                const sourceCell = this.getCell(data.idx, data.row + '-' + data.col);
                const targetCell = this.getCell(idx, row + '-' + col);
                if (!sourceCell || !targetCell) return;

                if (sourceCell.value) {
                    const targetGrid = this.getGrid(idx) as MeshGrid;
                    const exists = targetGrid.rows.some((r: MeshRow) =>
                        Object.keys(r).some((k: string) =>
                            (r as any)[k] !== sourceCell &&
                            (r as any)[k] !== targetCell &&
                            (r as any)[k].value === sourceCell.value,
                        ),
                    );
                    if (exists) return;
                }

                targetCell.value = sourceCell.value;
                targetCell.display = sourceCell.display;
                sourceCell.value = '';
                sourceCell.display = '';
            },

            /**
             * Cell 拖拽结束。
             *
             * <p>如果 dropEffect 为 'none'（未成功放置到有效目标），
             * 则清空源 Cell 的 value/display 数据。</p>
             */
            onCellDragEnd(this: any, event: DragEvent, idx: number, row: number, col: number) {
                if (event.dataTransfer!.dropEffect === 'none') {
                    const cell = this.getCell(idx, row + '-' + col);
                    if (cell && (cell.value || cell.display)) {
                        cell.value = '';
                        cell.display = '';
                    }
                }
            },
        };
    }

    // ── 实例方法 ─────────────────────────────────────────────────────

    /** 获取拖拽引擎实例 */
    getXUIMeshDrag(): XUIMeshDrag {
        return this.meshDrag;
    }

    /**
     * 元素连接到 DOM 时注册全局 mousemove / mouseup 监听，
     * 使拖拽操作在 Shadow DOM 外也能正常工作。
     */
    connectedCallback(): void {
        document.addEventListener('mousemove', this.meshDrag.onDraggingMove.bind(this.meshDrag));
        document.addEventListener('mouseup', this.meshDrag.onDraggingPlace.bind(this.meshDrag));
    }

    /**
     * 元素从 DOM 移除时注销全局事件监听。
     */
    disconnectedCallback(): void {
        document.removeEventListener('mousemove', this.meshDrag.onDraggingMove);
        document.removeEventListener('mouseup', this.meshDrag.onDraggingPlace);
    }

    /** 属性变化回调，子类可覆盖 */
    attributeChangedCallback(_attr: string, _oval: any, _nval: any): void {
        // 子类可覆盖
    }

    /**
     * 初始化布局表格。
     *
     * <p>调用 Vue 方法 loadLayoutTable 加载数据。
     * Vue created 钩子已将 loadLayoutTable 复制到元素实例上。</p>
     *
     * @param data MeshLayout JSON 数据
     */
    initXUIMeshLayout(data: any): void {
        (this as any).loadLayoutTable?.(data);
    }

    // ── 辅助 ─────────────────────────────────────────────────────────

    /** 判断对象是否为 DOM 元素 */
    private isDom(o: any): boolean {
        if (o === undefined) return false;
        return (typeof HTMLElement === 'object')
            ? (o instanceof HTMLElement)
            : (o && typeof o === 'object' && o.nodeType === 1 && typeof o.nodeName === 'string');
    }
}
